// Function to set a cookie
function setCookie(name, value, days) {
    const date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    const expires = "expires=" + date.toUTCString();
    document.cookie = name + "=" + (value || "") + ";" + expires + ";path=/";
}

// Function to get a cookie
function getCookie(name) {
    const nameEQ = name + "=";
    const ca = document.cookie.split(';');
    for(let i=0; i < ca.length; i++) {
        let c = ca[i];
        while (c.charAt(0) === ' ') c = c.substring(1, c.length);
        if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
    }
    return null;
}

// Function to hash a password
function sha256(str) {
    // Simple implementation of SHA-256 for demonstration purposes
    const crypto = window.crypto || window.msCrypto;
    const buf = new TextEncoder().encode(str);
    return crypto.subtle.digest('SHA-256', buf).then(hash => {
        let hexStr = '';
        const arrBuffView = new Uint8Array(hash);
        for (let i = 0; i < arrBuffView.byteLength; i++) {
            let hex = arrBuffView[i].toString(16);
            if (hex.length === 1) hex = '0' + hex;
            hexStr += hex;
        }
        return hexStr;
    });
}

